module.exports = function(RED) {
    function CustomOutputNode(config) {
        RED.nodes.createNode(this, config);
        const node = this;
        node.name = config.name;
        node.text = config.text;

        node.on("input", function(msg) {
            msg.payload = `Processed by agent node: ${node.name || ""}`;
            node.send(msg);
        });
    }

    RED.nodes.registerType("Custom Output",CustomOutputNode);
}